// Фильтрация и дедупликация новостей
const items = $input.all();
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

// Убираем дубликаты и фильтруем по времени
const uniqueNews = [];
const seenUrls = new Set();

for (const item of items) {
  const data = item.json;

  // Проверяем дату публикации
  const pubDate = new Date(data.pubDate || data.isoDate);
  if (pubDate < yesterday) continue;

  // Проверяем на дубликаты
  if (seenUrls.has(data.link)) continue;
  seenUrls.add(data.link);

  // Берем все доступные поля контента
  const rssContent = data['content:encodedSnippet'] || data.content || data.contentSnippet || data.summary || '';

  // Очищаем RSS контент от HTML
  const cleanRssContent = rssContent
    .replace(/<[^>]*>/g, '')
    .replace(/&[^;]+;/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  // Создаем новый объект, теперь с сохранением contentSnippet
  uniqueNews.push({
    title: data.title,
    link: data.link,
    rssContent: cleanRssContent,
    contentSnippet: data.contentSnippet, // Сохраняем оригинальный contentSnippet
    pubDate: data.pubDate,
    source: data['dc:creator'] || data.meta?.title || 'Unknown',
    guid: data.guid
  });
}

console.log(`Filtered ${uniqueNews.length} unique news from ${items.length} total`);

return uniqueNews.map(item => ({ json: item }));

// 1. Получаем все входящие элементы в виде массива
const allItems = $input.all();

// 2. Из каждого элемента забираем только его 'json' часть (саму новость)
// и складываем в новый массив.
const newsArray = allItems.map(item => item.json);

// 3. Возвращаем ОДИН-ЕДИНСТВЕННЫЙ новый элемент.
// У этого элемента будет поле 'data', которое содержит массив всех новостей.
// Имя 'data' важно, так как оно используется в промте: {{$json.data}}
return [{
  json: {
    data: newsArray
  }
}];

// Получаем длинный текст из предыдущего узла (AI-агента)
const longText = $json.output;

// Устанавливаем максимальную длину сообщения в Telegram
const maxLength = 4096;

// Место, где мы будем хранить готовые куски сообщения
const chunks = [];

let remainingText = longText;

// Запускаем цикл, который будет работать, пока не "нарежем" весь текст
while (remainingText.length > 0) {
  // Если оставшийся текст уже помещается в одно сообщение, просто добавляем его и выходим
  if (remainingText.length <= maxLength) {
    chunks.push(remainingText);
    break;
  }

  // Если текст слишком длинный, ищем последнее "красивое" место для разрыва
  // (двойной перенос строки) в пределах лимита
  let splitAt = remainingText.lastIndexOf('\n\n', maxLength);

  // Если не нашли двойного переноса (например, одна новость сама по себе > 4096 символов),
  // то просто ищем последний перенос строки
  if (splitAt === -1) {
    splitAt = remainingText.lastIndexOf('\n', maxLength);
  }

  // Если даже обычного переноса не нашли, режем "по живому", чтобы избежать бесконечного цикла
  if (splitAt === -1) {
      splitAt = maxLength;
  }

  // "Откусываем" кусок и добавляем его в наш массив
  chunks.push(remainingText.substring(0, splitAt));

  // Обновляем оставшийся текст
  remainingText = remainingText.substring(splitAt).trim();
}

// На выходе мы получаем массив из нескольких элементов,
// каждый из которых содержит кусок текста для отправки.
// Мы должны вернуть их в формате, который n8n сможет обработать по одному.
return chunks.map(chunk => ({
  json: {
    // Узел Telegram по умолчанию ищет текст в поле 'text'.
    // Мы сразу кладем наш кусок в это поле.
    text: chunk
  }
}));
